import type { PrismaClient } from "@prisma/client";
import { prisma as defaultPrisma } from "./client.js";

/**
 * Tracks which chat admins were promoted through Modryva (via /promote),
 * as opposed to promoted directly in Telegram, bypassing the bot. Read back
 * by the external-admin audit command (`detectExternalPromotions` in
 * modules/security/src/external-admin.ts) to diff against Telegram's live
 * `getChatAdministrators` result and flag any admin id this repository never
 * recorded. This is audit/alert bookkeeping only — it never grants, revokes,
 * or otherwise enforces admin rights; it just remembers who the bot promoted.
 */
export interface KnownAdminRepository {
  /** Marks `adminId` as a known (Modryva-tracked) admin for this chat. Idempotent. */
  addKnownAdmin(
    tenantId: string,
    chatId: string,
    adminId: bigint,
  ): Promise<void>;
  /** Every admin id tracked as known for this chat, in no particular order. */
  listKnownAdmins(
    tenantId: string,
    chatId: string,
  ): Promise<readonly bigint[]>;
  /**
   * Stops tracking `adminId` as known for this chat (e.g. after a /demote).
   * A no-op if the id was never tracked.
   */
  removeKnownAdmin(
    tenantId: string,
    chatId: string,
    adminId: bigint,
  ): Promise<void>;
}

export class PrismaKnownAdminRepository implements KnownAdminRepository {
  constructor(private readonly client: PrismaClient = defaultPrisma) {}

  async addKnownAdmin(
    tenantId: string,
    chatId: string,
    adminId: bigint,
  ): Promise<void> {
    await this.client.knownAdmin.upsert({
      where: { tenantId_chatId_adminId: { tenantId, chatId, adminId } },
      create: { tenantId, chatId, adminId },
      update: {},
    });
  }

  async listKnownAdmins(
    tenantId: string,
    chatId: string,
  ): Promise<readonly bigint[]> {
    const rows = await this.client.knownAdmin.findMany({
      where: { tenantId, chatId },
    });
    return rows.map((row) => row.adminId);
  }

  async removeKnownAdmin(
    tenantId: string,
    chatId: string,
    adminId: bigint,
  ): Promise<void> {
    await this.client.knownAdmin.deleteMany({
      where: { tenantId, chatId, adminId },
    });
  }
}

/** Store en memoria usado como default del constructor (tests). */
export class InMemoryKnownAdminRepository implements KnownAdminRepository {
  private readonly byChat = new Map<string, Set<bigint>>();

  private keyFor(tenantId: string, chatId: string): string {
    return `${tenantId} ${chatId}`;
  }

  async addKnownAdmin(
    tenantId: string,
    chatId: string,
    adminId: bigint,
  ): Promise<void> {
    const key = this.keyFor(tenantId, chatId);
    const set = this.byChat.get(key) ?? new Set<bigint>();
    set.add(adminId);
    this.byChat.set(key, set);
  }

  async listKnownAdmins(
    tenantId: string,
    chatId: string,
  ): Promise<readonly bigint[]> {
    const set = this.byChat.get(this.keyFor(tenantId, chatId));
    return set ? [...set] : [];
  }

  async removeKnownAdmin(
    tenantId: string,
    chatId: string,
    adminId: bigint,
  ): Promise<void> {
    this.byChat.get(this.keyFor(tenantId, chatId))?.delete(adminId);
  }
}

security.repositoryTestFileContent:
import { describe, expect, it } from "vitest";
import { InMemoryKnownAdminRepository } from "./known-admin-repository.js";

describe("InMemoryKnownAdminRepository", () => {
  it("tracks a known admin per (tenant, chat)", async () => {
    const repo = new InMemoryKnownAdminRepository();
    await repo.addKnownAdmin("t1", "c1", 111n);
    expect(await repo.listKnownAdmins("t1", "c1")).toEqual([111n]);
    expect(await repo.listKnownAdmins("t1", "c2")).toEqual([]);
  });

  it("is idempotent when the same admin is added twice", async () => {
    const repo = new InMemoryKnownAdminRepository();
    await repo.addKnownAdmin("t1", "c1", 111n);
    await repo.addKnownAdmin("t1", "c1", 111n);
    expect(await repo.listKnownAdmins("t1", "c1")).toEqual([111n]);
  });

  it("keeps admins for different chats of the same tenant distinct", async () => {
    const repo = new InMemoryKnownAdminRepository();
    await repo.addKnownAdmin("t1", "c1", 111n);
    await repo.addKnownAdmin("t1", "c2", 222n);
    expect(await repo.listKnownAdmins("t1", "c1")).toEqual([111n]);
    expect(await repo.listKnownAdmins("t1", "c2")).toEqual([222n]);
  });

  it("keeps admins for different tenants of the same chat id distinct", async () => {
    const repo = new InMemoryKnownAdminRepository();
    await repo.addKnownAdmin("t1", "c1", 111n);
    await repo.addKnownAdmin("t2", "c1", 222n);
    expect(await repo.listKnownAdmins("t1", "c1")).toEqual([111n]);
    expect(await repo.listKnownAdmins("t2", "c1")).toEqual([222n]);
  });

  it("removes a known admin", async () => {
    const repo = new InMemoryKnownAdminRepository();
    await repo.addKnownAdmin("t1", "c1", 111n);
    await repo.addKnownAdmin("t1", "c1", 222n);
    await repo.removeKnownAdmin("t1", "c1", 111n);
    expect(await repo.listKnownAdmins("t1", "c1")).toEqual([222n]);
  });

  it("removing an untracked admin is a no-op", async () => {
    const repo = new InMemoryKnownAdminRepository();
    await repo.removeKnownAdmin("t1", "c1", 999n);
    expect(await repo.listKnownAdmins("t1", "c1")).toEqual([]);
  });

  it("returns an empty list for a chat that has never had a known admin", async () => {
    const repo = new InMemoryKnownAdminRepository();
    expect(await repo.listKnownAdmins("t1", "unknown-chat")).toEqual([]);
  });
});

