    if (update.command?.name !== "auditoria_admins_externos") {
      return null;
    }

    const chatId = update.chat.chatId;
    if (!chatId || !context.chatId) {
      return { text: "Este comando se usa dentro de un grupo." };
    }

    if (!(await this.isGroupAdmin(chatId, update.user.userId))) {
      return {
        text: "Solo los administradores del grupo pueden auditar admins externos.",
      };
    }

    let admins: readonly {
      userId: bigint;
      username: string | undefined;
      firstName: string | undefined;
      isOwner: boolean;
      customTitle: string | undefined;
    }[];
