   * cannot promote; the creator and anyone promoted directly in Telegram
   * (outside this bot, and thus absent from knownAdminRepository) may.
   *
   * lastActionMs: the admin's most recent recorded decision in THIS chat
   * via adminDecisionRepository (aggressive-admin/consistency-check
   * workstream). See botUpdateServiceIntegrationNotes — until `.record()`
   * calls are wired at the moderation/admin-tool action sites, this is
   * always empty and every dangerous permission will show as stale, which
   * is safe (over-flagging) but not yet discriminating.
   */
  private async handlePermissionAuditCommand(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    if (update.command?.name !== "auditoria_permisos") {
      return null;
    }

    const chatId = update.chat.chatId;
    if (!chatId || !context.chatId) {
      return { text: "Este comando se usa dentro de un grupo." };
    }

    if (!(await this.isGroupAdmin(chatId, update.user.userId))) {
      return {
        text: "Solo los administradores de este grupo pueden ver la auditoría de permisos.",
      };
    }

    const adminsResult = await this.telegramGateway.getChatAdministrators({
      chatId,
      token: this.telegramToken(),
    });
    const admins = adminsResult.admins ?? [];
    if (admins.length === 0) {
      return {
        text: "No pude leer la lista de administradores de este grupo.",
      };
    }

    const [knownAdmins, recentDecisions] = await Promise.all([
      this.knownAdminRepository.listKnownAdmins(
        context.tenantId,
        context.chatId,
      ),
      this.adminDecisionRepository.listRecent(
        context.tenantId,
        context.chatId,
        500,
      ),
    ]);
    const knownAdminIds = new Set(knownAdmins);

    // listRecent is sorted newest-first, so the first hit per admin id is
    // their most recent decision.
    const lastActionMsByAdmin = new Map<string, number>();
    for (const decision of recentDecisions) {
      const key = decision.adminId.toString();
      if (!lastActionMsByAdmin.has(key)) {
        lastActionMsByAdmin.set(key, decision.occurredAt.getTime());
      }
    }

    const STALE_DAYS = 30;
    const adminPerms: AdminPerms[] = admins.map((admin) => {
      const userId = admin.userId.toString();
      const lastActionMs = lastActionMsByAdmin.get(userId);
      return {
        userId,
        canBan: true,
        canDelete: true,
        canPin: true,
        canPromote: admin.isOwner || !knownAdminIds.has(admin.userId),
        ...(lastActionMs !== undefined ? { lastActionMs } : {}),
      };
    });

    const findings = findExcessPermissions(
      adminPerms,
      Date.now(),
      STALE_DAYS * 24 * 60 * 60 * 1000,
    );

    if (findings.length === 0) {
      return {
        text: "🛡️ Auditoría de permisos de administrador: no se detectaron excesos de privilegio. Este comando solo informa, no revoca nada.",
      };
    }

    const nameFor = (telegramUserId: string): string => {
      const admin = admins.find(
        (a) => a.userId.toString() === telegramUserId,
      );
      if (!admin) {
        return telegramUserId;
      }
      return admin.username
        ? `@${admin.username}`
        : (admin.firstName ?? telegramUserId);
    };

    const lines = findings.map(
      (finding) => `• ${nameFor(finding.userId)}: ${finding.reason}`,
    );

    return {
      text: [
        "🛡️ Auditoría de permisos de administrador (solo informe, no revoca nada):",
        ...lines,
        "",
        `⚠️ Telegram no expone aquí los permisos exactos de cada admin, así que se asume acceso total salvo para promover (los admins que promoví yo nunca lo tienen). "Sin actividad reciente" son ${STALE_DAYS} días sin una acción de moderación tuya en este grupo.`,
      ].join("\n"),
    };
  }

// ── 7. Register the handler in botHandlers() (currently lines 1116-...), e.g. right after the
//        existing "admin-tool.command" entry at lines 1561-1565 ──
      {
        name: "permission-audit.command",
        handle: ({ context, update }) =>
          this.handlePermissionAuditCommand(context, update),
      },

