    // past the short-window limit above. Uses its own long-window bucket
    // (a separate key, `slow:${key}`) on the SAME FloodCounterStore, so it
    // never corrupts the short-window burst bucket. It only fires when the
    // burst path did NOT already trigger, and — critically — it reuses
    // `settings.action` (the admin's OWN configured antiflood action) rather
    // than inventing a new one, so it can never be harsher than what's
    // already configured, and if the admin set action to "ignore" this is
    // still a no-op below, exactly like the burst path.
    const slowFloodWindowSeconds = settings.windowSeconds * 12;
