          }
        : burstDecision;

    if (!decision.triggered || decision.action === "ignore") {
      return null;
    }

    await this.floodCounter.reset(key);
    await this.floodCounter.reset(slowKey);

// (Everything below this point — recordEvent, sanction creation, audit,
// reply text — is UNCHANGED and keeps referencing `decision` exactly as
// before; `decision.count`/`decision.action` now transparently reflect
// whichever path fired.)

// ── 4) REPLACE the ENTIRE detectRaid() method body with: ────────────────

  private async detectRaid(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<void> {
    if (!context.chatId || !update.chat.chatId) {
      return;
    }

    const settings = await this.loadAntiraidSettings(context);

    if (!settings.enabled) {
      return;
    }

    const now = Date.now();
    const key = `raid:${context.chatId}`;
    let timestamps: readonly number[] = [];
    for (let index = 0; index < update.newChatMemberIds.length; index += 1) {
      timestamps = await this.floodCounter.record(
        key,
        now,
        settings.windowSeconds,
      );
    }

    const burstDecision = evaluateRaid([...timestamps], now, settings);

    // Name-similarity: ADDITIONAL signal alongside the join-burst counter
    // above. FloodCounterStore only tracks timestamps, not names, so this
    // uses the new RaidJoinNameStore, keyed the same way (same window) so
    // both signals see the same rolling window of joins.
    const nameKey = `raidnames:${context.chatId}`;
    let recentJoins: readonly RaidJoin[] = [];
    for (const memberId of update.newChatMemberIds) {
      const name = this.extractJoinName(update.raw, memberId);
      recentJoins = await this.raidJoinNames.record(
        nameKey,
        name,
        now,
        settings.windowSeconds,
      );
    }
    const nameSignal = detectRaidSignals(
      recentJoins,
      settings.windowSeconds * 1000,
      now,
    ).find((signal) => signal.key === "raid_name_similarity");

    // The name-similarity signal only ever ADDS a second way to reach the
    // SAME gated decision: `settings.enabled` is still required above, and
    // `settings.mode` (observe vs enforce) below is the admin's own
    // configured mode — never a new unconditional action, and it never
    // double-fires on top of the burst path.
    const triggered = burstDecision.triggered || (nameSignal?.present ?? false);

    if (!triggered) {
      return;
    }

    const joinCount = burstDecision.triggered
      ? burstDecision.joinCount
      : recentJoins.length;
    const mode = burstDecision.mode;

    await this.antiraidRepository.recordEvent({
      tenantId: context.tenantId,
      chatId: context.chatId,
      joinCount,
      windowSeconds: settings.windowSeconds,
      mode,
    });
    await this.antiraidRepository.setUnderAttack(
      context.chatId,
      new Date(now + settings.windowSeconds * 1000),
    );

    if (mode === "enforce") {
      for (const memberId of update.newChatMemberIds) {
        try {
          await this.telegramGateway.restrictChatMember({
            chatId: update.chat.chatId,
            userId: memberId,
            token: this.telegramToken(),
            untilDate: undefined,
          });
        } catch {
          // Enforcement failures never block alerting/audit.
        }
      }
    }

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "system",
      action: "antiraid.triggered",
      resourceType: "antiraid_event",
      resourceId: context.chatId,
      payload: {
        joinCount,
        mode,
        windowSeconds: settings.windowSeconds,
        ...(nameSignal?.present ? { nameSimilarity: true } : {}),
      },
    });

    await this.emitOwnerNetworkRoute({
      context,
      sourceChatId: context.chatId,
      eventKind: "raid_alerts",
      fallbackEventKind: "logs",
      title: "Alerta de raid",
      body: [
        `Grupo: ${update.chat.chatId?.toString() ?? context.chatId}`,
        `Entradas: ${joinCount} en ${settings.windowSeconds}s`,
        `Modo: ${mode}`,
        ...(nameSignal?.detail ? [`Señal adicional: ${nameSignal.detail}`] : []),
      ].join("\n"),
    });
  }

  /**
   * Best-effort join-name extraction from the raw Telegram update (does NOT
   * touch packages/telegram/src/normalize.ts — normalize.ts discards names
   * and only keeps IDs in `newChatMemberIds`, so this reads `update.raw`
   * directly, mirroring normalize.ts's own bot-filtering logic).
   */
  private extractJoinName(raw: unknown, userId: bigint): string {
    const message = (
      raw as {
        message?: {
          new_chat_members?: ReadonlyArray<{
            id: number;
            is_bot?: boolean;
            first_name?: string;
            username?: string;
          }>;
        };
      }
    )?.message;
    const match = (message?.new_chat_members ?? []).find(
      (member) => !member.is_bot && BigInt(member.id) === userId,
    );
    return match?.first_name ?? match?.username ?? `id:${userId.toString()}`;
  }

