  /**
   * A fresh batch of trivia questions for the solo/inline arcade, drawn from the
   * full 5000+ bank. Deterministic per (user, round) so a reload returns the
   * same batch, but each new round advances to different questions — giving
   * effectively unlimited solo play. Includes correctIndex (the arcade scores
   * client-side; submitted scores are still capped server-side by the catalog).
   *
   * Adaptive difficulty: the caller's level (1..5) is tracked per
   * (tenant, chat, user) in QuizDifficultyRepository, defaulting to 1. When
   * `answers` (the PREVIOUS batch's outcome: how many of the last batch's
   * questions were answered, and how many correctly) is supplied, accuracy()/
   * nextDifficulty() update the stored level before this batch is picked.
   * KNOWN GAP: TRIVIA_QUESTIONS carries no difficulty tag today (see note
   * above), so the level is persisted and returned for the client to display
   * but does not yet change which questions are selected.
   */
  async quizBatch(
    userId: string,
    round: number,
    size = 8,
    startParam: string | null = null,
    bot?: BotScope,
    answers?: { correct: number; total: number },
  ): Promise<{
    round: number;
    difficulty: QuizDifficulty;
    questions: Array<{
      question: string;
      options: string[];
      correctIndex: number;
    }>;
  }> {
    const pool = TRIVIA_QUESTIONS;
    if (pool.length === 0) {
      throw new ServiceUnavailableException({ error: "no-trivia" });
    }
    const tenantId = await this.tenantId(bot);
    const { chatId } = await this.resolveScope(
      startParam,
      userId,
      tenantId,
      bot,
    );
    const uid = BigInt(userId);
    const currentLevel = (await this.quizDifficulty.getLevel(
      tenantId,
      chatId,
      uid,
    )) as QuizDifficulty;
    let difficulty = currentLevel;
    if (answers) {
      difficulty = nextDifficulty(currentLevel, answers);
      if (difficulty !== currentLevel) {
        await this.quizDifficulty.setLevel(tenantId, chatId, uid, difficulty);
      }
    }
    const safeRound = Number.isFinite(round) ? Math.trunc(round) : 0;
    const start = dailyTriviaHash(`${userId}:${safeRound}`) % pool.length;
    const questions: Array<{
      question: string;
      options: string[];
      correctIndex: number;
    }> = [];
    for (let i = 0; i < size; i += 1) {
      const q = pool[(start + i) % pool.length];
      if (q) {
        questions.push({
          question: q.question,
          options: [...q.options],
          correctIndex: q.correctIndex,
        });
      }
    }
    return { round: safeRound, difficulty, questions };
  }

