model BracketTournament {
  id             String    @id @default(cuid())
  tenantId       String
  chatId         String
  status         String    @default("open") // open | done
  entrants       Json // string[] original full entrant list (audit/display)
  currentRound   Int       @default(1)
  pendingMatches Json // BracketMatch[] ({a,b}) of the current round still awaiting a recorded winner
  roundWinners   Json // string[] winners resolved so far this round (recorded wins + automatic byes)
  champion       String?
  createdAt      DateTime  @default(now())
  updatedAt      DateTime  @updatedAt

  @@index([tenantId, chatId, status])
  @@map("bracket_tournaments")
}

// Suggested placement: right after the existing `model Tournament { ... }` block
// (~line 2243-2257, casino weekly prize-pool), before the
// "// --- D1 control center MVP ---" comment — keeps it visually next to, but
// clearly distinct from, the unrelated Tournament model.

