      since tokens.ts wasn't on the do-not-edit list):
   apps/bot/src/tokens.ts now has, after GUARDIAN_REPOSITORY:
     export const BATTLE_ENTRIES_REPOSITORY = Symbol("BATTLE_ENTRIES_REPOSITORY");
   ============================================================ */

/* ============================================================
   2) imports to add in apps/bot/src/bot-update.service.ts
   ============================================================ */

// -- in the `import type { ... } from "@superbot/data"` block (line ~5-63):
// insert alphabetically, right after "AutomationRepository," and before
// "CaptchaFailAction,":
  BattleEntriesRepository,
  BattleKind,

// -- in the plain `import { ... } from "@superbot/data"` block (line ~64-89):
// insert alphabetically, right after "InMemoryAutomationRepository," and
// before "InMemoryChatActivityRepository,":
  InMemoryBattleEntriesRepository,

// -- in the `import { ... } from "@superbot/module-games"` block (line ~326-371):
// insert alphabetically:
//   after "resolveBullseye," and before "resolveDebateDuel,":
  resolveCreativityChallenge,
//   after "resolveOverUnder," and before "resolveSlot,":
  resolvePlaylistBattle,
// also add these two type-only imports to the same block (or a `type {...}`
// import from "@superbot/module-games" right after it):
  type CreativityChallengeEntry,
  type SongVotes,

// -- in the `import { ... } from "./tokens.js"` block (line ~621-672):
// insert alphabetically, right after "AUTOMATION_REPOSITORY," and before
// "CAPTCHA_REPOSITORY,":
  BATTLE_ENTRIES_REPOSITORY,

/* ============================================================
   3) module-level constant — add near `configuredPlatformAdminRoles`
      (top-level const, right after the import block, ~line 674)
   ============================================================ */

const BATTLE_GAME_KINDS: readonly {
  readonly kind: BattleKind;
  readonly label: string;
}[] = [
  { kind: "playlist", label: "🎵 Batalla de playlists" },
  { kind: "creativity", label: "🎨 Reto de creatividad" },
];

/* ============================================================
   4) constructor parameter — add inside the BotUpdateService
      constructor's @Optional-injected block, right after
      `chatSettingRepository` and before `guardianRepository`
      (~line 899, same pattern as every other @Optional repo):
   ============================================================ */

    @Optional()
    @Inject(BATTLE_ENTRIES_REPOSITORY)
    private readonly battleEntriesRepository: BattleEntriesRepository = new InMemoryBattleEntriesRepository(),

/* ============================================================
   5) botHandlers() registration — add one entry anywhere in the
      array returned by `private botHandlers()` (~line 1116 onward),
      e.g. right next to the existing "trivia.command" / "trivia.answer"
      entries (~line 1539-1546). Dispatch is first-non-null-wins
      (dispatchUpdate, ~line 1104), and no other handler claims
      "playlist_batalla" / "reto_creativo" / "enviar" / "votar" /
      "cerrar_playlist_batalla" / "cerrar_reto_creativo", so placement
      order doesn't matter functionally:
   ============================================================ */

      {
        name: "battle.command",
        handle: ({ context, update }) =>
          this.handleBattleCommand(context, update),
      },

/* ============================================================
   6) private methods — add anywhere among the other private
      handle* methods (e.g. right after handleTriviaAnswer, ~line 5707)
   ============================================================ */

  private async handleBattleCommand(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    const name = update.command?.name;
    if (!name) {
      return null;
    }

    if (name === "playlist_batalla") {
      return this.openBattleRound(context, update, "playlist");
    }
    if (name === "reto_creativo") {
      return this.openBattleRound(context, update, "creativity");
    }
    if (name === "enviar") {
      return this.submitBattleEntry(context, update);
    }
    if (name === "votar") {
      return this.voteBattleEntry(context, update);
    }
    if (name === "cerrar_playlist_batalla") {
      return this.closeBattleRound(context, update, "playlist");
    }
    if (name === "cerrar_reto_creativo") {
      return this.closeBattleRound(context, update, "creativity");
    }

    return null;
  }

  private battleSettingKey(kind: BattleKind): string {
    return `battle_open_round:${kind}`;
  }

  private async getOpenBattleRound(
    context: FoundationContext,
    kind: BattleKind,
  ): Promise<string | undefined> {
    if (!context.chatId) {
      return undefined;
    }
    const raw = await this.chatSettingRepository.getValue(
      context.tenantId,
      context.chatId,
      this.battleSettingKey(kind),
    );
    if (
      typeof raw === "object" &&
      raw !== null &&
      (raw as { open?: boolean }).open === true &&
      typeof (raw as { roundId?: unknown }).roundId === "string"
    ) {
      return (raw as { roundId: string }).roundId;
    }
    return undefined;
  }

  private async openBattleRound(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
    kind: BattleKind,
  ): Promise<BotReply | null> {
    const game = BATTLE_GAME_KINDS.find((entry) => entry.kind === kind);
    const label = game?.label ?? "Batalla";

    if (!context.chatId) {
      return { text: `${label} se juega dentro de un grupo.` };
    }

    const existingRoundId = await this.getOpenBattleRound(context, kind);
    if (existingRoundId) {
      return {
        text: `${label} ya está abierta. Usa /enviar <contenido> para participar, o /votar <entryId> para votar.`,
      };
    }

    const roundId = randomUUID();
    await this.chatSettingRepository.setValue(
      context.tenantId,
      context.chatId,
      this.battleSettingKey(kind),
      {
        open: true,
        roundId,
        openedBy: update.user.userId?.toString() ?? null,
        openedAt: new Date().toISOString(),
      },
    );

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "user",
      action: "game.battle.opened",
      resourceType: "battle_round",
      resourceId: roundId,
      ...(context.userId ? { actorId: context.userId } : {}),
      payload: { kind },
    });

    return {
      text: `${label} está abierta. Envía tu participación con /enviar <contenido>. Vótala luego con /votar <entryId> (el id te lo doy al enviar).`,
    };
  }

  private async submitBattleEntry(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    if (!context.chatId || !update.user.userId) {
      return { text: "Envía tu participación dentro de un grupo." };
    }

    const content = (update.command?.args ?? [])
      .join(" ")
      .trim()
      .slice(0, 200);
    if (!content) {
      return {
        text: "Uso: /enviar <contenido> (una canción para la batalla de playlists, o un meme/idea para el reto creativo).",
      };
    }

    const openRounds: {
      readonly kind: BattleKind;
      readonly label: string;
      readonly roundId: string;
    }[] = [];
    for (const game of BATTLE_GAME_KINDS) {
      const roundId = await this.getOpenBattleRound(context, game.kind);
      if (roundId) {
        openRounds.push({ kind: game.kind, label: game.label, roundId });
      }
    }

    if (openRounds.length === 0) {
      return {
        text: "No hay ninguna batalla abierta. Usa /playlist_batalla o /reto_creativo para abrir una.",
      };
    }

    if (openRounds.length > 1) {
      return {
        text: `Hay varias batallas abiertas a la vez (${openRounds
          .map((round) => round.label)
          .join(" y ")}). Pide a un admin que cierre una antes de enviar.`,
      };
    }

    const target = openRounds[0];
    if (!target) {
      return null;
    }

    const result = await this.battleEntriesRepository.submitEntry(
      context.tenantId,
      context.chatId,
      target.kind,
      target.roundId,
      update.user.userId,
      content,
    );

    if (result.outcome === "duplicate") {
      return {
        text: `Ya enviaste tu participación en ${target.label}. Solo se admite una por ronda.`,
      };
    }

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "user",
      action: "game.battle.submitted",
      resourceType: "battle_entry",
      resourceId: result.entry.id,
      ...(context.userId ? { actorId: context.userId } : {}),
      payload: { kind: target.kind, roundId: target.roundId },
    });

    return {
      text: `✅ Enviado a ${target.label}: "${content}"\nId para votar: ${result.entry.id}`,
    };
  }

  private async voteBattleEntry(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    if (!context.chatId || !update.user.userId) {
      return { text: "Vota dentro de un grupo." };
    }

    const entryId = (update.command?.args ?? [])[0]?.trim();
    if (!entryId) {
      return { text: "Uso: /votar <entryId>" };
    }

    let hadOpenRound = false;
    for (const game of BATTLE_GAME_KINDS) {
      const roundId = await this.getOpenBattleRound(context, game.kind);
      if (!roundId) {
        continue;
      }
      hadOpenRound = true;

      const result = await this.battleEntriesRepository.voteEntry(
        context.tenantId,
        context.chatId,
        game.kind,
        roundId,
        entryId,
        update.user.userId,
      );

      if (result.outcome === "voted") {
        await this.repository.recordAudit({
          tenantId: context.tenantId,
          actorType: "user",
          action: "game.battle.voted",
          resourceType: "battle_entry",
          resourceId: entryId,
          ...(context.userId ? { actorId: context.userId } : {}),
          payload: { kind: game.kind, roundId },
        });
        return { text: "🗳️ ¡Voto registrado!" };
      }
      if (result.outcome === "self-vote") {
        return { text: "No puedes votar tu propia participación." };
      }
      if (result.outcome === "duplicate") {
        return { text: "Ya usaste tu voto en esta ronda." };
      }
      // "not-found" in this round: entryId might belong to the other open
      // round (if both games are open at once), keep looking.
    }

    return {
      text: hadOpenRound
        ? "No encontré esa participación en la batalla abierta."
        : "No hay ninguna batalla abierta ahora mismo.",
    };
  }

  private async closeBattleRound(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
    kind: BattleKind,
  ): Promise<BotReply | null> {
    const game = BATTLE_GAME_KINDS.find((entry) => entry.kind === kind);
    const label = game?.label ?? "Batalla";

    if (!context.chatId) {
      return { text: `${label} se cierra dentro de un grupo.` };
    }

    if (!(await this.isActorAdmin(context, update))) {
      return { text: "Solo un admin o moderador puede cerrar la batalla." };
    }

    const roundId = await this.getOpenBattleRound(context, kind);
    if (!roundId) {
      return { text: `${label} no está abierta ahora mismo.` };
    }

    const records = await this.battleEntriesRepository.listRoundEntries(
      context.tenantId,
      context.chatId,
      kind,
      roundId,
    );

    // Clear the open-round pointer regardless of outcome so a new round can
    // start; submitted entries stay in the table as history.
    await this.chatSettingRepository.setValue(
      context.tenantId,
      context.chatId,
      this.battleSettingKey(kind),
      { open: false, roundId, closedAt: new Date().toISOString() },
    );

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "user",
      action: "game.battle.closed",
      resourceType: "battle_round",
      resourceId: roundId,
      ...(context.userId ? { actorId: context.userId } : {}),
      payload: { kind, entryCount: records.length },
    });

    if (records.length === 0) {
      return {
        text: `${label} ha cerrado sin participaciones. ¡Nadie ganó esta vez!`,
      };
    }

    const byId = new Map(records.map((entry) => [entry.id, entry] as const));

    if (kind === "playlist") {
      const ranking = resolvePlaylistBattle(
        records.map(
          (entry): SongVotes => ({ songId: entry.id, votes: entry.votes }),
        ),
      );
      const top = ranking[0];
      const winnerEntry = top ? byId.get(top.songId) : undefined;
      const lines = ranking
        .slice(0, 5)
        .map(
          (rank, index) =>
            `${index + 1}. ${byId.get(rank.songId)?.content ?? "?"} — ${rank.votes} votos`,
        );
      return {
        text: [
          `🏆 ${label} ha cerrado.`,
          `Ganador: "${winnerEntry?.content ?? "?"}" con ${top?.votes ?? 0} votos.`,
          "",
          ...lines,
        ].join("\n"),
      };
    }

    const result = resolveCreativityChallenge(
      records.map(
        (entry): CreativityChallengeEntry => ({
          id: entry.id,
          votes: entry.votes,
        }),
      ),
    );
    const winnerEntry = result.winnerId ? byId.get(result.winnerId) : undefined;
    const topVotes = result.ranking[0]?.votes ?? 0;
    const lines = result.ranking
      .slice(0, 5)
      .map(
        (rank, index) =>
          `${index + 1}. ${byId.get(rank.id)?.content ?? "?"} — ${rank.votes} votos`,
      );
    return {
      text: [
        `🏆 ${label} ha cerrado.`,
        `Ganador: "${winnerEntry?.content ?? "?"}" con ${topVotes} votos.`,
        "",
        ...lines,
      ].join("\n"),
    };
  }

games.repositoryFileContent:
import {
  InMemoryChatActivityRepository,
  PrismaChatActivityRepository,
  type ChatActivityRepository,
} from "./chat-activity-repository.js";

/**
 * Real vote counter for "duelo de debate" (`/duelo_debate`): counts distinct
 * Telegram users who reacted to a debater's designated message, so the game
 * uses genuine reactions instead of a moderator typing vote totals by hand.
 *
 * Telegram's `message_reaction` update only exposes newly-added emoji per
 * event (see `packages/telegram/src/normalize.ts`'s `emojisAdded`), not a
 * historical reaction count and not removals. So rather than a
 * "getMessageReactionCount"-style read, this repository accumulates votes
 * live: the bot's reaction handler calls `recordVote` on every reaction-add
 * event, and `/duelo_debate` later calls `getVoteCount` to read the tally.
 *
 * Storage rides on the existing `ChatActivityRepository` (kind
 * "debate_vote") instead of a bespoke table, following this repo's "one
 * flexible log backs many small per-message counters" pattern (see
 * `chat-activity-repository.ts` and `chat-setting-repository.ts`) — no new
 * Prisma model needed.
 *
 * KNOWN LIMITATION: because only additions are observable, a voter who
 * removes their reaction is still counted (their vote is never retracted).
 * This is an accepted trade-off, not a bug — flagged for anyone extending
 * this later if Telegram/normalize.ts ever exposes removals.
 */
export interface DebateDuelVoteRepository {
  /**
   * Registers `voterId` as having reacted to `messageId` in `chatId`.
   * Idempotent: a voter who already has a recorded vote for this exact
   * message is a no-op, so repeated reaction-add events from the same user
   * (e.g. switching emoji) never double-count their vote.
   */
  recordVote(
    tenantId: string,
    chatId: string,
    messageId: bigint,
    voterId: bigint,
  ): Promise<void>;

  /** Number of distinct voters recorded for `messageId` in this chat. */
  getVoteCount(
    tenantId: string,
    chatId: string,
    messageId: bigint,
  ): Promise<number>;
}

/** Activity-log `kind` this repository scopes itself to. Internal. */
const DEBATE_VOTE_KIND = "debate_vote";

/** Cap on how many recent votes are scanned per chat when counting. Internal. */
const MAX_SCANNED_VOTES = 1000;

const recordVoteVia = async (
  activity: ChatActivityRepository,
  tenantId: string,
  chatId: string,
  messageId: bigint,
  voterId: bigint,
): Promise<void> => {
  const existing = await activity.findUserEvent(
    tenantId,
    chatId,
    DEBATE_VOTE_KIND,
    voterId,
    messageId,
  );
  if (existing) {
    return;
  }
  await activity.record({
    tenantId,
    chatId,
    kind: DEBATE_VOTE_KIND,
    telegramUserId: voterId,
    messageId,
  });
};

const getVoteCountVia = async (
  activity: ChatActivityRepository,
  tenantId: string,
  chatId: string,
  messageId: bigint,
): Promise<number> => {
  const recent = await activity.listRecent(
    tenantId,
    chatId,
    DEBATE_VOTE_KIND,
    MAX_SCANNED_VOTES,
  );
  const voters = new Set<string>();
  for (const entry of recent) {
    if (entry.messageId === messageId && entry.telegramUserId !== undefined) {
      voters.add(entry.telegramUserId.toString());
    }
  }
  return voters.size;
};

/**
 * Production implementation: delegates to a `ChatActivityRepository`
 * (Prisma-backed by default), so votes persist in the existing
 * `ChatActivityEvent` table under kind "debate_vote". No new table.
 */
export class PrismaDebateDuelVoteRepository implements DebateDuelVoteRepository {
  constructor(
    private readonly activity: ChatActivityRepository = new PrismaChatActivityRepository(),
  ) {}

  async recordVote(
    tenantId: string,
    chatId: string,
    messageId: bigint,
    voterId: bigint,
  ): Promise<void> {
    await recordVoteVia(this.activity, tenantId, chatId, messageId, voterId);
  }

  async getVoteCount(
    tenantId: string,
    chatId: string,
    messageId: bigint,
  ): Promise<number> {
    return getVoteCountVia(this.activity, tenantId, chatId, messageId);
  }
}

/** Store en memoria usado como default del constructor (tests). */
export class InMemoryDebateDuelVoteRepository
  implements DebateDuelVoteRepository
{
  constructor(
    private readonly activity: ChatActivityRepository = new InMemoryChatActivityRepository(),
  ) {}

  async recordVote(
    tenantId: string,
    chatId: string,
    messageId: bigint,
    voterId: bigint,
  ): Promise<void> {
    await recordVoteVia(this.activity, tenantId, chatId, messageId, voterId);
  }

  async getVoteCount(
    tenantId: string,
    chatId: string,
    messageId: bigint,
  ): Promise<number> {
    return getVoteCountVia(this.activity, tenantId, chatId, messageId);
  }
}

